import 'dart:convert';

/// Model representing the structured output of a child behavioral assessment.
/// Generated by the MindCare Child Behavioral Assessment Engine.
class ChildAssessmentResult {
  final String childId;
  final String childName;
  final String riskLevel; // "stable" | "monitor" | "concern" | "urgent"
  final double confidence; // 0.0–1.0
  final Map<String, int> domainSignals; // emotional_dysregulation, anxiety_indicators, etc. 0–10
  final List<String> behaviorChangesFromBaseline;
  final List<String> possibleTriggers;
  final List<RecommendedAction> recommendedActions;
  final bool escalateToDoctor;
  final String? escalationReason;
  final List<String> suggestedTherapyModules;
  final int followUpInDays; // 3 | 7 | 14
  final String? summaryForDoctor;

  ChildAssessmentResult({
    required this.childId,
    required this.childName,
    required this.riskLevel,
    required this.confidence,
    required this.domainSignals,
    required this.behaviorChangesFromBaseline,
    required this.possibleTriggers,
    required this.recommendedActions,
    required this.escalateToDoctor,
    this.escalationReason,
    required this.suggestedTherapyModules,
    required this.followUpInDays,
    this.summaryForDoctor,
  });

  /// Create from JSON map.
  factory ChildAssessmentResult.fromJson(Map<String, dynamic> json) {
    return ChildAssessmentResult(
      childId: json['child_id'] ?? '',
      childName: json['child_name'] ?? '',
      riskLevel: json['risk_level'] ?? 'stable',
      confidence: (json['confidence'] as num?)?.toDouble() ?? 0.0,
      domainSignals: Map<String, int>.from(json['domain_signals'] ?? {}),
      behaviorChangesFromBaseline: List<String>.from(json['behavior_changes_from_baseline'] ?? []),
      possibleTriggers: List<String>.from(json['possible_triggers'] ?? []),
      recommendedActions: (json['recommended_actions'] as List?)
          ?.map((e) => RecommendedAction.fromJson(e))
          .toList() ?? [],
      escalateToDoctor: json['escalate_to_doctor'] ?? false,
      escalationReason: json['escalation_reason'],
      suggestedTherapyModules: List<String>.from(json['suggested_therapy_modules'] ?? []),
      followUpInDays: json['follow_up_in_days'] ?? 7,
      summaryForDoctor: json['summary_for_doctor'],
    );
  }

  /// Convert to JSON map.
  Map<String, dynamic> toJson() {
    return {
      'child_id': childId,
      'child_name': childName,
      'risk_level': riskLevel,
      'confidence': confidence,
      'domain_signals': domainSignals,
      'behavior_changes_from_baseline': behaviorChangesFromBaseline,
      'possible_triggers': possibleTriggers,
      'recommended_actions': recommendedActions.map((e) => e.toJson()).toList(),
      'escalate_to_doctor': escalateToDoctor,
      'escalation_reason': escalationReason,
      'suggested_therapy_modules': suggestedTherapyModules,
      'follow_up_in_days': followUpInDays,
      'summary_for_doctor': summaryForDoctor,
    };
  }

  /// Parse from the AI response text that contains <child_assessment_result> tags.
  static ChildAssessmentResult? fromResponseText(String responseText) {
    final startTag = '<child_assessment_result>';
    final endTag = '</child_assessment_result>';

    final startIndex = responseText.indexOf(startTag);
    final endIndex = responseText.indexOf(endTag);

    if (startIndex == -1 || endIndex == -1 || endIndex <= startIndex) {
      return null;
    }

    final jsonString = responseText.substring(startIndex + startTag.length, endIndex).trim();

    try {
      final jsonMap = jsonDecode(jsonString);
      return ChildAssessmentResult.fromJson(jsonMap);
    } catch (e) {
      return null;
    }
  }
}

/// Model for recommended actions in the assessment.
class RecommendedAction {
  final String type; // "activity" | "parent_strategy" | "professional_review" | "urgent"
  final String title;
  final String reason;
  final String priority; // "immediate" | "this_week" | "next_appointment"

  RecommendedAction({
    required this.type,
    required this.title,
    required this.reason,
    required this.priority,
  });

  factory RecommendedAction.fromJson(Map<String, dynamic> json) {
    return RecommendedAction(
      type: json['type'] ?? '',
      title: json['title'] ?? '',
      reason: json['reason'] ?? '',
      priority: json['priority'] ?? '',
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'type': type,
      'title': title,
      'reason': reason,
      'priority': priority,
    };
  }
}